using namespace std;

struct compare {
    bool operator()(const ListNode* a, const ListNode* b) {
        return a->val > b->val;
    }
};

class Solution {
public:
    ListNode* mergeKLists(vector<ListNode*>& lists) {
        if (lists.empty()) return nullptr;

        priority_queue<ListNode*, vector<ListNode*>, compare> heap;

        for (auto& list : lists) {
            if (list) {
                heap.push(list);
            }
        }

        ListNode dummy(0);
        ListNode* tail = &dummy;

        while (!heap.empty()) {
            auto current = heap.top();
            heap.pop();

            tail->next = current;
            tail = tail->next;

            if (current->next) {
                heap.push(current->next);
            }
        }

        return dummy.next;
    }
};

